    '數位介面供電（VDDI 電源平面之一）': { en: 'Digital-interface supply (one of the VDDI power planes)', ja: 'デジタルインタフェース電源（VDDI 電源プレーンの一つ）', ko: '디지털 인터페이스 전원(VDDI 전원 플레인 중 하나)' },
    '共用輸出端（OUT，共 C2/C3/D1/D2/D3/D4 六球）': { en: 'Shared output (OUT; six balls C2/C3/D1/D2/D3/D4)', ja: '共用出力（OUT、C2/C3/D1/D2/D3/D4 の 6 ボール）', ko: '공용 출력(OUT, C2/C3/D1/D2/D3/D4 6개 볼)' },
    '內部基準輸出；接 100nF 到 GND': { en: 'Internal reference output; connect 100nF to GND', ja: '内部基準出力；100nF を GND へ接続', ko: '내부 기준 출력; 100nF을 GND에 연결' },
    '側 1 接地': { en: 'Side 1 ground', ja: '側 1 グラウンド', ko: '측 1 접지' },
    '側 2 接地': { en: 'Side 2 ground', ja: '側 2 グラウンド', ko: '측 2 접지' },
    '正電源': { en: 'Positive supply', ja: '正電源', ko: '양 전원' },
