    'DAC 同步更新（active-low）': { en: 'DAC synchronous update (active-low)', ja: 'DAC 同期更新（active-low）', ko: 'DAC 동기 업데이트(active-low)' },
    'DAC 相關類比腳；ADC 通道/封裝球位：B0/C26': { en: 'DAC-related analog pin; ADC channel / package ball: B0/C26', ja: 'DAC 関連アナログピン；ADC チャネル/パッケージボール：B0/C26', ko: 'DAC 관련 아날로그 핀; ADC 채널/패키지 볼: B0/C26' },
