    'OUT_B+ 高側閘極驅動 bootstrap 電容連接點': { en: 'OUT_B+ high-side gate-drive bootstrap-capacitor connection point', ja: 'OUT_B+ ハイサイドゲート駆動 bootstrap コンデンサ接続点', ko: 'OUT_B+ 하이사이드 게이트 구동 bootstrap 커패시터 접속점' },
