    'PMBus 雙向序列資料腳(datasheet TYPE 欄標示為 I)': { en: 'PMBus bidirectional serial-data pin (marked as I in the datasheet TYPE column)', ja: 'PMBus 双方向シリアルデータピン（datasheet TYPE 欄では I と表示）', ko: 'PMBus 양방향 직렬 데이터 핀(datasheet TYPE 열에는 I로 표시)' },
