    '來源 B': { en: 'Source B', ja: 'ソース B', ko: '소스 B' },
    '來源 B（可輸入或輸出）': { en: 'Source B (can be input or output)', ja: 'ソース B（入力または出力可）', ko: '소스 B(입력 또는 출력 가능)' },
    '來源端（可輸入或輸出）': { en: 'Source terminal (can be input or output)', ja: 'ソース端子（入力または出力可）', ko: '소스 단자(입력 또는 출력 가능)' },
    '來源選擇（低=選 A、高=選 B）': { en: 'Source select (low = A, high = B)', ja: 'ソース選択（低=A、高=B）', ko: '소스 선택(로우=A, 하이=B)' },
    '保留腳。懸空（floating）。': { en: 'Reserved pin. Leave floating.', ja: '予約ピン。浮遊（floating）。', ko: '예약 핀. 부유(floating).' },
