    '側 1 接地（VCC1 參考）': { en: 'Side 1 ground (referenced to VCC1)', ja: '側 1 グラウンド（VCC1 基準）', ko: '측 1 접지(VCC1 기준)' },
    '側 1 接地（參考 VCC1）': { en: 'Side 1 ground (referenced to VCC1)', ja: '側 1 グラウンド（VCC1 参照）', ko: '측 1 접지(VCC1 참조)' },
    '側 1 輸出致能（高/開路致能）': { en: 'Side 1 output enable (high/open enables)', ja: '側 1 出力イネーブル（高/オープンで有効）', ko: '측 1 출력 인에이블(하이/개방으로 활성)' },
