    '側 1 電源（2.25~5.5V）；接 100nF 到 GND1': { en: 'Side 1 supply (2.25–5.5V); connect 100nF to GND1', ja: '側 1 電源（2.25～5.5V）；100nF を GND1 へ接続', ko: '측 1 전원(2.25~5.5V); 100nF을 GND1에 연결' },
