    '傳送資料輸入': { en: 'Transmit data input', ja: '送信データ入力', ko: '송신 데이터 입력' },
    '傳送輸出電平設定；接 12.1kΩ 1% 電阻到地': { en: 'Transmit output-level setting; connect a 12.1kΩ 1% resistor to ground', ja: '送信出力レベル設定；12.1kΩ 1% 抵抗を接地へ接続', ko: '송신 출력 레벨 설정; 12.1kΩ 1% 저항을 접지에 연결' },
    '元件接地': { en: 'Device ground', ja: 'デバイスグラウンド', ko: '소자 접지' },
